mapper.sql:
C.CUST_DELFLG = '0' AND C.CUST_NM LIKE CONCAT('%', #{custNm}, '%')
AND C.CUST_INFOR_SECURITY = #{custInforSecurity}
AND C.CUST_DISPATCH = #{custDispatch}
AND EXISTS ( SELECT 1 FROM MANG_TBL M WHERE M.MANAGER_CUST_ID = C.CUST_ID AND M.MANAGER_NM LIKE CONCAT('%', #{managerNm}, '%') )

mapper.delete:
DELETE FROM MANG_TBL
WHERE MANAGER_CD = #{managerCd}
  AND MANAGER_CHRCD = #{managerChrcd}
  AND MANAGER_CUST_ID = #{managerCustId}
